import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"千相之器·无我之形","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/千相之器·无我之形.md","filePath":"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/千相之器·无我之形.md"}'),_={name:"4.资源分区/7.物品与装备/2.武器/魔法武器/6.可升级/千相之器·无我之形.md"};function d(p,a,l,b,i,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"千相之器·无我之形",tabindex:"-1"},[s("千相之器·无我之形 "),e("a",{class:"header-anchor",href:"#千相之器·无我之形","aria-label":'Permalink to "千相之器·无我之形"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="千相之器·无我之形-1" tabindex="-1">千相之器·无我之形 <a class="header-anchor" href="#千相之器·无我之形-1" aria-label="Permalink to &quot;千相之器·无我之形&quot;">​</a></h1><p>在某处悬浮着一块混沌原质。它无形无相，触之如液态星光，遇念则沸腾。古卷称其为“万化胚胎”——能折射一切存在的可能性。</p><p>直到一群无名匠人掘出胚胎。他们以星尘为砧，引力为锤，将胚胎锻造成一方巴掌大的银灰色金属块。当最后一道淬火完成时，金属块表面浮现两枚古篆：千相。<br> ————————————<br> 本武器需要逐级购买，而非差价升级</p><p>千相之器·无我之形<br> D+1000<br> 千相之器·无我之形在未购买时是一个法术强度为6 破魔2 破甲2，体积为3的球状体，在使用者购买后其外观由使用者自行决定，其体积在1-5中选择，可附魔，可进行材质升级。<br> 在使用者获得此法器后，同时获得一个10立方米的储物空间【千相之境】，此空间不可存储【千相之器·无我之形】并且仅能存储死物，存储和取出将使用一个迅捷动作。</p><p>C+1000<br> 此时的武器上有了更加繁复的花纹，其上微微散发着细密的白光，让使用者觉得无比的温暖<br> 购买此等级后，千相之器·无我之形的法术强度提升至14 破魔2 破甲2<br> 【无相】现在使用者的施法攻击具有C级措手不及的效果<br> 【多面】当你佩戴千相之器时，你的施法攻击额外获得5点破甲，若这部分破防仍有剩余则转化为攻击上的器械加值，至多转化5点。</p><p>B+2000<br> 现在整个千相之器的内部完全玉化，整个武器氤氲着静谧的灵韵，有着静心的效果让人安心。<br> 购买此等级后，千相之器的法术强度提升至21 破魔2 破甲2<br> 在战斗中，现在的千相之器可以帮助使用者打出更加沉重的伤害，使用者的施法攻击获得【湮灭】【超级贯穿】<br> 在战斗中，使用者可以冷静地观察敌人的每一个破绽，在使用者使用此武器进行施法攻击时，再获得基于使用者（感知属性/2）的破甲。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(_,[["render",d]]);export{f as __pageData,m as default};
